<?php namespace App\Http\Controllers; use App\Models\{Asset,PreventiveMaintenance,WorkOrder};use App\Services\DashboardService; class DashboardController extends Controller{public function index(DashboardService $service){return view('dashboard.index',['metrics'=>$service->metrics(),'activity'=>$service->activity(),'statusCounts'=>WorkOrder::selectRaw('status,count(*) total')->groupBy('status')->pluck('total','status'),'categoryCounts'=>Asset::selectRaw('category,count(*) total')->groupBy('category')->pluck('total','category'),'calendar'=>PreventiveMaintenance::with('asset')->orderBy('next_maintenance')->take(8)->get()]);}}
